// ChatMessageModal.jsx - Updated with real API
import React, { useState, useEffect, useRef } from "react";
import { X, Send } from "lucide-react";
import {
    initSocket,
    getMessages,
    sendMessage,
    onNewMessage,
    joinConversation,
    leaveConversation,
    emitTypingStart,
    emitTypingEnd,
    emitMarkAsRead
} from "../../../api/chatApi";
import axios from "axios";
export default function ChatMessageModal({ onClose, currentUser, selectedUser }) {
    const [messages, setMessages] = useState([]);
    const [messageInput, setMessageInput] = useState("");
    const [isTyping, setIsTyping] = useState(false);
    const [conversation, setConversation] = useState(null);
    const messagesEndRef = useRef(null);
    const typingTimeoutRef = useRef(null);
    const socketRef = useRef(null);

    useEffect(() => {
        // Initialize socket
        socketRef.current = initSocket(currentUser.id, currentUser.type);

        // Get or create conversation
        getOrCreateConversation();

        return () => {
            if (conversation?.conversation_id) {
                leaveConversation(conversation.conversation_id);
            }
        };
    }, []);

    const getOrCreateConversation = async () => {
        const response = await axios.post("/api/user/chat/get-or-create-conversation", {
            participant1_type: currentUser.type,
            participant1_id: currentUser.id,
            participant2_type: selectedUser.type,
            participant2_id: selectedUser.id
        });

        if (response.data.success) {
            setConversation(response.data.conversation);
            joinConversation(response.data.conversation.conversation_id);
            loadMessages(response.data.conversation.conversation_id);
            emitMarkAsRead(response.data.conversation.conversation_id, currentUser.id, currentUser.type);
        }
    };

    const loadMessages = async (conversationId) => {
        const response = await getMessages(conversationId, currentUser.id, currentUser.type);
        if (response.data.success) {
            setMessages(response.data.messages);
            scrollToBottom();
        }
    };

    // Socket event listeners
    useEffect(() => {
        if (!socketRef.current) return;

        onNewMessage((newMessage) => {
            if (newMessage.conversation_id === conversation?.conversation_id) {
                setMessages(prev => [...prev, newMessage]);
                scrollToBottom();
                emitMarkAsRead(conversation.conversation_id, currentUser.id, currentUser.type);
            }
        });

        return () => {
            if (socketRef.current) {
                socketRef.current.disconnect();
            }
        };
    }, [conversation]);

    const handleSendMessage = async () => {
        if (!messageInput.trim()) return;

        const tempId = Date.now();
        const newMsg = {
            id: tempId,
            message: messageInput,
            isMe: true,
            created_at: new Date(),
            sender_name: currentUser.name
        };

        setMessages(prev => [...prev, newMsg]);
        setMessageInput("");
        scrollToBottom();

        await sendMessage(
            conversation.conversation_id,
            currentUser.type, currentUser.id,
            selectedUser.type, selectedUser.id,
            messageInput
        );
    };

    const handleTyping = (e) => {
        setMessageInput(e.target.value);

        if (!isTyping) {
            setIsTyping(true);
            emitTypingStart(conversation.conversation_id, currentUser.name);
        }

        clearTimeout(typingTimeoutRef.current);
        typingTimeoutRef.current = setTimeout(() => {
            setIsTyping(false);
            emitTypingEnd(conversation.conversation_id, currentUser.name);
        }, 1000);
    };

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    return (
        <div style={styles.modalOverlay}>
            <div style={styles.modalContainer}>
                {/* Left Sidebar - User List */}
                <div style={styles.sidebar}>
                    <div style={styles.sidebarHeader}>
                        <h5>Messages</h5>
                        <button onClick={onClose} style={styles.closeBtn}>
                            <X size={20} />
                        </button>
                    </div>
                    <div style={styles.userList}>
                        {/* User list from API */}
                    </div>
                </div>

                {/* Right Side - Chat Area */}
                <div style={styles.chatArea}>
                    <div style={styles.chatHeader}>
                        <img src={selectedUser.avatar} alt={selectedUser.name} style={styles.avatar} />
                        <div>
                            <h6>{selectedUser.name}</h6>
                            <span style={styles.roleBadge}>{selectedUser.role}</span>
                        </div>
                    </div>

                    <div style={styles.messagesArea}>
                        {messages.map((msg) => (
                            <div key={msg.id} style={{
                                ...styles.messageRow,
                                justifyContent: msg.isMe ? "flex-end" : "flex-start"
                            }}>
                                <div style={{
                                    ...styles.messageBubble,
                                    backgroundColor: msg.isMe ? "#ff3e43" : "#fff",
                                    color: msg.isMe ? "#fff" : "#212529"
                                }}>
                                    <p>{msg.message}</p>
                                    <span style={styles.messageTime}>
                                        {new Date(msg.created_at).toLocaleTimeString()}
                                    </span>
                                </div>
                            </div>
                        ))}
                        <div ref={messagesEndRef} />
                    </div>

                    <div style={styles.inputArea}>
                        <input
                            type="text"
                            placeholder="Type your message..."
                            value={messageInput}
                            onChange={handleTyping}
                            onKeyPress={(e) => e.key === "Enter" && handleSendMessage()}
                            style={styles.input}
                        />
                        <button onClick={handleSendMessage} style={styles.sendBtn}>
                            <Send size={18} color="#fff" />
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
}

const styles = {
    modalOverlay: {
        position: "fixed",
        top: 0, left: 0, right: 0, bottom: 0,
        backgroundColor: "rgba(0,0,0,0.7)",
        zIndex: 99999,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        backdropFilter: "blur(8px)"
    },
    modalContainer: {
        width: "90%",
        maxWidth: "1200px",
        height: "80vh",
        backgroundColor: "#fff",
        borderRadius: "16px",
        display: "flex",
        overflow: "hidden",
        boxShadow: "0 20px 60px rgba(0,0,0,0.3)"
    },
    sidebar: {
        width: "320px",
        borderRight: "1px solid #e9ecef",
        display: "flex",
        flexDirection: "column",
        backgroundColor: "#f8f9fa"
    },
    sidebarHeader: {
        padding: "20px",
        borderBottom: "1px solid #e9ecef",
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center"
    },
    closeBtn: {
        background: "none",
        border: "none",
        cursor: "pointer",
        padding: "4px"
    },
    userList: {
        flex: 1,
        overflowY: "auto"
    },
    chatArea: {
        flex: 1,
        display: "flex",
        flexDirection: "column"
    },
    chatHeader: {
        padding: "20px",
        borderBottom: "1px solid #e9ecef",
        display: "flex",
        alignItems: "center",
        gap: "12px"
    },
    avatar: {
        width: "40px",
        height: "40px",
        borderRadius: "50%",
        objectFit: "cover"
    },
    roleBadge: {
        fontSize: "11px",
        padding: "2px 8px",
        borderRadius: "4px",
        backgroundColor: "#f44336",
        color: "#fff"
    },
    messagesArea: {
        flex: 1,
        overflowY: "auto",
        padding: "20px",
        display: "flex",
        flexDirection: "column",
        gap: "12px",
        backgroundColor: "#f8f9fa"
    },
    messageRow: {
        display: "flex"
    },
    messageBubble: {
        maxWidth: "70%",
        padding: "10px 14px",
        borderRadius: "12px",
        boxShadow: "0 1px 2px rgba(0,0,0,0.1)"
    },
    messageTime: {
        fontSize: "10px",
        color: "rgba(0,0,0,0.5)",
        display: "block",
        marginTop: "4px"
    },
    inputArea: {
        padding: "20px",
        borderTop: "1px solid #e9ecef",
        display: "flex",
        gap: "12px",
        backgroundColor: "#fff"
    },
    input: {
        flex: 1,
        padding: "10px 14px",
        border: "1px solid #e9ecef",
        borderRadius: "24px",
        outline: "none",
        fontSize: "14px"
    },
    sendBtn: {
        backgroundColor: "#ff3e43",
        border: "none",
        borderRadius: "50%",
        width: "40px",
        height: "40px",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        cursor: "pointer"
    }
};